}
else
{
    <span class="badge bg-success rounded-pill ms-2">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Use InvokeAsync because the alert may fire from a timer (non-Blazor thread).
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

