@page "/dashboard"
@using sv_1e285af3ebfa4aada7be726507bf8b99.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IAsyncDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-5">
            <strong>@WarehouseState.CurrentWarehouseName</strong>
            <span class="text-muted ms-2">(@WarehouseState.CurrentWarehouseId)</span>
        </p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Low-Stock Alerts
            <AlertBadge />
        </h5>
        <p class="card-text">
            @if (AlertService.LastLowStockCount > 0)
            {
                <span class="text-danger">
                    ⚠ @AlertService.LastLowStockCount item(s) below minimum stock level.
                </span>
            }
            else
            {
                <span class="text-success">✓ All items are above minimum stock levels.</span>
            }
        </p>
        <p class="text-muted"><small>Refreshes every 10 seconds while this page is open.</small></p>
    </div>
</div>

@code {
    private CancellationTokenSource _cts = new();
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        WarehouseState.OnChange += _warehouseHandler;

        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _alertHandler;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // Initial fetch, then start polling.
            await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
            _ = PollAsync(_cts.Token);
        }
    }

    private async Task OnWarehouseChanged()
    {
        // Warehouse changed — cancel current polling, refresh immediately, restart.
        await _cts.CancelAsync();
        _cts.Dispose();
        _cts = new CancellationTokenSource();

        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        StateHasChanged();
        _ = PollAsync(_cts.Token);
    }

    private async Task PollAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when navigating away or switching warehouse.
        }
    }

    public async ValueTask DisposeAsync()
    {
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;

        await _cts.CancelAsync();
        _cts.Dispose();
    }
}

